import{_ as t,o as r,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"22. Part Time Review Of Hours","description":"","frontmatter":{"title":"22. Part Time Review Of Hours","eba":"Health Allied & Managers Admin 2021-2025","topics":["employment","termination"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/employment-types/22-part-time-review-of-hours.md","filePath":"ebas/has-managers-admin/common-terms/employment-types/22-part-time-review-of-hours.md"}'),s={name:"ebas/has-managers-admin/common-terms/employment-types/22-part-time-review-of-hours.md"};function n(i,e,m,l,p,h){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_22-part-time-review-of-hours" tabindex="-1">22. Part Time Review Of Hours <a class="header-anchor" href="#_22-part-time-review-of-hours" aria-label="Permalink to &quot;22. Part Time Review Of Hours&quot;">​</a></h1><p><strong>22.1</strong> Where over a period of 26 weeks or more a part-time Employee regularly and systematically works more than their contracted hours, the Employer or the Employee may request in writing a contract reflecting that the Employee’s hours have increased on a permanent basis. Such a request will not be unreasonably refused by either party.</p><p>PART C – TYPES OF EMPLOYMENT AND TERMINATION OF EMPLOYMENT</p><p><strong>22.2</strong> Where the Employer makes the request under subclause 22.1, at the time of making the request the Employer will also notify the Employee in writing of their obligations under this subclause.</p><p><strong>22.3</strong> An Employee will not be considered to be regularly and systematically rostered if the shifts the Employee has been working are replacing an absent Employee (for example parental leave, long service leave, workers’ compensation or personal leave) or a temporary flexible work arrangement.</p><p><strong>22.4</strong> A written response will be provided no later than 21 days from the date of a request (by either an Employee or Employer).</p><p><strong>22.5</strong> Where the request is refused:</p><p><strong>(a)</strong> the written response will include reasons for the refusal.</p><p><strong>(b)</strong> an Employee may request that the Employer provides any evidence relied upon in making a determination under this clause.</p><p><strong>(c)</strong> where a dispute arises in relation to the response by either an Employer or an Employee, it will be dealt with in accordance with <a href="/eba/ebas/has-managers-admin/common-terms/consultation-disputes/17-dispute-resolution-procedure.html">Clause 17</a> (Dispute Resolution Procedure).</p><p><strong>22.6</strong> Where the request is granted:</p><p><strong>(a)</strong> the Employee will be provided with a Letter of Appointment setting out the revised employment arrangements.</p>',12)])])}const c=t(s,[["render",n]]);export{d as __pageData,c as default};
